package genxsolution.vms.vmsbackend.employee_hr_management.payroll.service;
import genxsolution.vms.vmsbackend.employee_hr_management.exception.HrResourceNotFoundException; import genxsolution.vms.vmsbackend.employee_hr_management.payroll.dto.*; import genxsolution.vms.vmsbackend.employee_hr_management.payroll.mapper.PayrollMapper; import genxsolution.vms.vmsbackend.employee_hr_management.payroll.repository.PayrollRepository; import org.springframework.stereotype.Service; import java.util.*;
@Service public class PayrollService { private final PayrollRepository repository; private final PayrollMapper mapper; public PayrollService(PayrollRepository repository,PayrollMapper mapper){this.repository=repository;this.mapper=mapper;} public List<PayrollResponse> list(UUID companyId){ return repository.findAll(companyId).stream().map(mapper::toResponse).toList(); } public PayrollResponse getById(UUID id){ return repository.findById(id).map(mapper::toResponse).orElseThrow(() -> new HrResourceNotFoundException("Payroll", id.toString())); } public PayrollResponse create(PayrollUpsertRequest r){ return mapper.toResponse(repository.create(r)); } public PayrollResponse update(UUID id,PayrollUpsertRequest r){ return repository.update(id,r).map(mapper::toResponse).orElseThrow(() -> new HrResourceNotFoundException("Payroll", id.toString())); } public void delete(UUID id){ if(!repository.delete(id)) throw new HrResourceNotFoundException("Payroll", id.toString()); } }
